	require.NoError(t, os.WriteFile(seedFile, []byte("seed\n"), 0644))
	runGitInteg(t, workDir, "add", "seed.txt")
	runGitInteg(t, workDir, "commit", "-m", "chore: initial seed")
	runGitInteg(t, workDir, "push", "-u", "origin", "main")

