	}
	if err := trackerSyncFetchAndMerge(ctx, projectRoot, log, emit, "pre_claim"); err != nil {
		emitTrackerSyncAttention(log, emit, "pre_claim", "", "tracker_sync_merge_failed", err.Error())
	}
